        {
            if (eventData.IsMouseButNotLeft())
                return;
            var id = choosingBlueprints?[index];
            if (commandBlock)
            {
                if (!CanChooseCommandBlockBlueprint(id))
                    return;
                ChooseCommandBlockBlueprint(id);
                chooseUI.HideCommandBlockPanel();
                RemovePanelFlag(PanelFlags.CommandBlock);
            }
            else
