        #region 面板标识符
        private void AddPanelFlag(PanelFlags flag)
        {
            panelFlags |= flag;
        }
        private void RemovePanelFlag(PanelFlags flag)
        {
            panelFlags &= ~flag;
        }
        private void ClearPanelFlags()
        {
            panelFlags = PanelFlags.None;
        }
        private bool HasPanelFlags()
        {
            return panelFlags != PanelFlags.None;
